import React, { useEffect, useMemo, useState } from 'react';
import Calendar from 'react-calendar';
import { FiClock } from 'react-icons/fi';
import { bookingApi } from '../../api/bookingApi';
import { useAuth } from '../../context/AuthContext';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import ErrorAlert from '../../components/common/ErrorAlert';
import BookingStatusBadge from './BookingStatusBadge';
import BookingsTabs from './BookingsTabs';
import 'react-calendar/dist/Calendar.css';

const BookingCalendar = () => {
	const { isAdmin } = useAuth();
	const adminView = isAdmin();

	const [selectedDate, setSelectedDate] = useState(new Date());
	const [bookings, setBookings] = useState([]);
	const [loading, setLoading] = useState(true);
	const [error, setError] = useState(null);

	useEffect(() => {
		const load = async () => {
			try {
				setLoading(true);
				const data = adminView ? await bookingApi.getAllBookings({}) : await bookingApi.getUserBookings(1);
				setBookings(Array.isArray(data) ? data : []);
				setError(null);
			} catch (err) {
				setError('Failed to load bookings');
			} finally {
				setLoading(false);
			}
		};

		load();
	}, [adminView]);

	const formatTime = (value) =>
		value
			? new Date(value).toLocaleTimeString(undefined, {
					hour: '2-digit',
					minute: '2-digit',
				})
			: '-';

	const dateKey = (date) => new Date(date).toDateString();

	const bookingsForDay = useMemo(() => {
		const selectedKey = dateKey(selectedDate);
		return bookings.filter((booking) => {
			if (!booking?.startTime) return false;
			return dateKey(booking.startTime) === selectedKey;
		});
	}, [bookings, selectedDate]);

	if (loading) return <LoadingSpinner />;

	return (
		<div className="booking-page">
			<div className="booking-page-header">
				<div>
					<h1>Booking Calendar</h1>
					<p>View bookings by date.</p>
				</div>
			</div>

			<BookingsTabs />

			{error ? <ErrorAlert message={error} /> : null}

			<section className="booking-calendar-card">
				<div className="booking-calendar-left">
					<Calendar onChange={setSelectedDate} value={selectedDate} />
				</div>
				<div className="booking-calendar-right">
					<h3 className="booking-calendar-title">Bookings on {selectedDate.toLocaleDateString()}</h3>

					{bookingsForDay.length === 0 ? (
						<p className="no-data">No bookings for this date.</p>
					) : (
						<div className="booking-calendar-list">
							{bookingsForDay.map((booking) => (
								<article key={booking.id} className="booking-calendar-item">
									<div className="booking-calendar-item-top">
										<div>
											<p className="booking-calendar-item-room">{booking.resourceName || 'Resource'}</p>
											<p className="booking-calendar-item-time">
												<FiClock aria-hidden="true" /> {formatTime(booking.startTime)} - {formatTime(booking.endTime)}
											</p>
										</div>
										<BookingStatusBadge status={booking.status} />
									</div>
									<p className="booking-calendar-item-purpose">{booking.purpose || 'No purpose provided'}</p>
								</article>
							))}
						</div>
					)}
				</div>
			</section>
		</div>
	);
};

export default BookingCalendar;
